## 目的

B2 で骨格を作った Sheet 内の Todo 1 件を担当する Accordion アイテムを実装する。impl markdown は Accordion を展開した時のみレンダリングする（Accordion の `value` ベース制御は不要、`AccordionContent` 内に置けば閉じている時はそもそもマウントされない）。

## ファイル

`dashboard/components/tasks-detail-todo.tsx`（新規）

## 実装内容

```typescript
'use client';

import { CheckCircle2, Circle } from 'lucide-react';
import Markdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

import {
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from '@/components/ui/accordion';
import { Badge } from '@/components/ui/badge';
import type { TasksJsonV2Todo } from '@/lib/types';

interface TasksDetailTodoProps {
  todo: TasksJsonV2Todo;
}

export function TasksDetailTodo({ todo }: TasksDetailTodoProps) {
  const completedSteps = todo.steps.filter((s) => s.checked).length;
  return (
    <AccordionItem value={todo.id} className="border rounded mb-2">
      <AccordionTrigger className="px-3 py-2 text-left hover:no-underline">
        <div className="flex items-center gap-2 min-w-0">
          <Badge variant="outline">{todo.id}</Badge>
          {todo.tdd && <Badge variant="secondary">TDD</Badge>}
          <span className="font-medium truncate">{todo.title}</span>
          <span className="text-xs text-muted-foreground tabular-nums shrink-0">
            {completedSteps}/{todo.steps.length}
          </span>
        </div>
      </AccordionTrigger>
      <AccordionContent className="px-3 py-3 space-y-4">
        {todo.description && (
          <p className="text-xs text-muted-foreground">{todo.description}</p>
        )}

        {todo.dependencies.length > 0 && (
          <p className="text-xs">
            <span className="text-muted-foreground">依存: </span>
            {todo.dependencies.join(', ')}
          </p>
        )}

        {todo.affectedFiles.length > 0 && (
          <div className="space-y-1">
            <h4 className="text-xs font-semibold">変更ファイル</h4>
            <ul className="space-y-1 text-xs">
              {todo.affectedFiles.map((f, i) => (
                <li key={i} className="flex items-start gap-2">
                  <Badge variant="outline" className="shrink-0">{f.operation}</Badge>
                  <div className="min-w-0">
                    <code className="break-all">{f.path}</code>
                    {f.summary && (
                      <p className="text-muted-foreground">{f.summary}</p>
                    )}
                  </div>
                </li>
              ))}
            </ul>
          </div>
        )}

        {todo.relatedIssues.length > 0 && (
          <p className="text-xs">
            <span className="text-muted-foreground">関連 Issue: </span>
            {todo.relatedIssues.join(', ')}
          </p>
        )}

        <div className="space-y-1">
          <h4 className="text-xs font-semibold">Steps</h4>
          <ul className="space-y-1 text-xs">
            {todo.steps.map((s, i) => (
              <li key={i} className="flex items-start gap-2">
                {s.checked ? (
                  <CheckCircle2 className="size-3.5 text-green-600 shrink-0 mt-0.5" />
                ) : (
                  <Circle className="size-3.5 text-muted-foreground shrink-0 mt-0.5" />
                )}
                <div className="min-w-0">
                  <span>{s.title}</span>
                  {s.kind === 'review' && s.review && (
                    <div className="mt-1 rounded bg-muted px-2 py-1 space-y-0.5">
                      <div className="flex items-center gap-2">
                        <Badge variant={s.review.result === 'PASSED' ? 'default' : 'destructive'}>
                          {s.review.result}
                        </Badge>
                        {typeof s.review.fixCount === 'number' && (
                          <span className="text-muted-foreground">fix: {s.review.fixCount}</span>
                        )}
                      </div>
                      {s.review.summary && <p className="text-muted-foreground">{s.review.summary}</p>}
                    </div>
                  )}
                </div>
              </li>
            ))}
          </ul>
        </div>

        {todo.impl && (
          <div className="space-y-1">
            <h4 className="text-xs font-semibold">実装手順</h4>
            <div className="prose prose-sm dark:prose-invert max-w-none rounded border bg-muted/30 px-3 py-2">
              <Markdown remarkPlugins={[remarkGfm]}>{todo.impl}</Markdown>
            </div>
          </div>
        )}
      </AccordionContent>
    </AccordionItem>
  );
}
```

## 注意点

- `react-markdown` と `remark-gfm` は既存 `plan-markdown-modal.tsx` で使われているため依存追加は不要
- `Badge` の `variant="default"` / `"destructive"` / `"secondary"` / `"outline"` の存在は既存テーマで確認済み
- impl は AccordionContent 内にあるため、Accordion が閉じている間はマウントされず描画コスト 0

